import json
import logging
import os
import sys
from flask import Flask, request

app = Flask(__name__)

class StructuredFormatter(logging.Formatter):
    def format(self, record):
        log = {
            "severity": record.levelname,
            "message": record.getMessage(),
            "logger": record.name,
        }
        # Attach trace ID from Cloud Trace header if present
        trace_header = request.headers.get("X-Cloud-Trace-Context", "")
        if trace_header:
            trace_id = trace_header.split("/")[0]
            log["logging.googleapis.com/trace"] = (
                f"projects/{os.environ.get('GOOGLE_CLOUD_PROJECT', '')}/traces/{trace_id}"
            )
        return json.dumps(log)

handler = logging.StreamHandler(sys.stdout)
handler.setFormatter(StructuredFormatter())
logging.root.handlers = [handler]
logging.root.setLevel(os.environ.get("LOG_LEVEL", "INFO"))
logger = logging.getLogger(__name__)

@app.route("/health")
def health():
    return {"status": "ok"}

@app.route("/process")
def process():
    logger.info("Processing request", extra={"user_id": "u123"})
    return {"processed": True}

import requests
import os
from flask import Flask, request

app = Flask(__name__)

def get_trace_headers():
    """Extract and forward trace context from incoming request."""
    headers = {}
    trace_header = request.headers.get("X-Cloud-Trace-Context")
    if trace_header:
        headers["X-Cloud-Trace-Context"] = trace_header
    return headers

@app.route("/api/order")
def create_order():
    # Forward trace headers to downstream service calls
    trace_headers = get_trace_headers()
    response = requests.post(
        "http://internal-payment-service/charge",
        json={"amount": 100},
        headers=trace_headers
    )
    return {"order_id": "123", "payment": response.json()}
